import { quicksort, binarySearch } from './src/sort.js';
import assert from 'node:assert/strict';

assert.deepEqual(quicksort([3, 1, 4, 1, 5, 9, 2, 6]), [1, 1, 2, 3, 4, 5, 6, 9]);
assert.deepEqual(quicksort([]), []);
assert.deepEqual(quicksort([1]), [1]);
assert.deepEqual(quicksort([5, 4, 3, 2, 1]), [1, 2, 3, 4, 5]);
assert.deepEqual(quicksort([1, 1, 1]), [1, 1, 1]);

const sorted = [1, 3, 5, 7, 9, 11, 13];
assert.equal(binarySearch(sorted, 7), 3);
assert.equal(binarySearch(sorted, 1), 0);
assert.equal(binarySearch(sorted, 13), 6);
assert.equal(binarySearch(sorted, 4), -1);
assert.equal(binarySearch(sorted, 0), -1);
assert.equal(binarySearch(sorted, 14), -1);
assert.equal(binarySearch([], 5), -1);

console.log('All tests passed');
